class Solution {
public:
    int minimumChanges(string s, int k) {
        int n = s.size();
        vector<vector<int>> dp(n + 1, vector<int>(k + 1, INT_MAX));
        dp[0][0] = 0;

        for (int i = 1; i <= n; ++i) {
            for (int j = 1; j <= min(i, k); ++j) {
                for (int prev = 0; prev < i; ++prev) {
                    int changes = getChanges(s, prev, i);
                    dp[i][j] = min(dp[i][j], dp[prev][j - 1] + changes);
                }
            }
        }

        return dp[n][k];
    }

    int getChanges(string& s, int start, int end) {
        int changes = 0;
        int n = end - start;

        for (int d = 1; d < n; ++d) {
            if (n % d != 0) continue;

            bool isSemiPalindrome = true;
            for (int i = 0; i < d; ++i) {
                char c = s[start + i];
                for (int j = i + d; j < n; j += d) {
                    if (s[start + j] != c) {
                        isSemiPalindrome = false;
                        break;
                    }
                }
                if (!isSemiPalindrome) break;
            }

            if (isSemiPalindrome) return changes;
        }

        // If not semi-palindrome, calculate changes
        int freq[26] = {0};
        for (int i = start; i < end; ++i) {
            ++freq[s[i] - 'a'];
        }

        int maxFreq = *max_element(freq, freq + 26);
        return end - start - maxFreq;
    }
};
